        </motion.p>
      </motion.header>

      <motion.main 
        className={styles.split_layout}
        initial="hidden"
        animate="visible"
        variants={containerVariants}
      >
        {/* LEFT PANEL: REGISTRATION QR & TRACKING */}
        <motion.section variants={itemVariants} className={styles.left_panel}>
          <TiltCard className={styles.glass_card_v2}>
