}

export const PhotoModal: React.FC<Props> = ({ selectedPhoto, previewScale, onClose, onSetPreviewScale }) => (
  <AnimatePresence>
    {selectedPhoto && (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
