import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ExternalLink, Users, RefreshCcw, LogOut, Clock, Activity } from 'lucide-react';
import { Visitor } from '../../src/store/index';
import styles from '../../app/approval/approval.module.css';

interface VisitorGridProps {
  visitors: Visitor[];
  isLoading: boolean;
  onAction: (visitor: Visitor, action: string) => void;
  onViewTraceability: (visitor: Visitor) => void;
  onViewPass: (visitor: Visitor) => void;
  statusLabels: Record<string, string>;
  getStatusClass: (status: string) => string;
  OverstayTimer: React.ComponentType<{ expectedCheckout?: string }>;
}

export const VisitorGrid: React.FC<VisitorGridProps> = ({
  visitors, isLoading, onAction, onViewTraceability, onViewPass, 
  statusLabels, getStatusClass, OverstayTimer
}) => {
  return (
    <div className={styles.lifecycle_grid}>
      {isLoading ? (
        Array.from({ length: 6 }).map((_, i) => (
          <div key={i} className={`glass-card ${styles.host_card_lifecycle}`} style={{ opacity: 0.5 }}>
            <div className={styles.card_top_info}>Loading...</div>
          </div>
        ))
      ) : (
        <AnimatePresence mode="popLayout">
          {visitors.map((req) => (
            <motion.div 
              key={req._id} 
              className={`glass-card ${styles.host_card_lifecycle} ${styles.pass_design}`} 
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              style={{ borderLeft: `6px solid var(--status-${req.status.toLowerCase().replace('_', '-')})` }}
              layout
            >
              <div className={styles.card_top_info} onClick={() => onViewPass(req)}>
                <div className={styles.visitor_biometrics}>
                  <div className={styles.v_initials}>
                     {req.photoUrl ? <img src={req.photoUrl} alt="" className={styles.v_photo_tiny} /> : req.name.substring(0,2).toUpperCase()}
                  </div>
                  <div className={styles.v_meta}>
                     <span className={styles.v_name_main}>{req.name}</span>
                     <span className={styles.v_id}>🏷️ ID: {req._id.substring(req._id.length - 6).toUpperCase()}</span>
                     <OverstayTimer expectedCheckout={req.expectedCheckout} />
                  </div>
                </div>
                <div className={`${styles.status_badge_v2} ${getStatusClass(req.status)}`}>
                   {statusLabels[req.status] || req.status}
                   <ExternalLink size={10} style={{ marginLeft: '4px' }} />
                </div>
              </div>

              <div className={styles.card_body_details}>
                <div className={styles.detail_node}><label>🎯 PURPOSE</label><strong>{req.purpose}</strong></div>
                <div className={styles.detail_node}><label>📅 TIME</label><strong>{new Date(req.visitTime || req.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</strong></div>
                <div className={styles.detail_node}><label>📞 CONTACT</label><strong>{req.company || 'Private'} • {req.phone}</strong></div>
              </div>

              <div className={styles.lifecycle_actions}>
                <button className={styles.timeline_trigger} onClick={() => onViewTraceability(req)}>
                   <Users size={14} style={{ marginRight: '8px' }} /> VIEW TRACEABILITY
                </button>

                {req.status === 'SENT_FOR_APPROVAL' && (
                  <div className={styles.dual_actions}>
                    <button className={`${styles.action_btn} ${styles.deny}`} onClick={() => onAction(req, 'REJECT')}>❌ REJECT</button>
                    <button className={`${styles.action_btn} ${styles.allow}`} onClick={() => onAction(req, 'APPROVE')}>✅ APPROVE</button>
                  </div>
                )}

                {req.status === 'APPROVED' && (
                  <div className={styles.waiting_stage}><RefreshCcw size={16} className={styles.spin_icon} /><span>WAITING AT GATE</span></div>
                )}

                {req.status === 'GATE_IN' && (
                  <div className={styles.dual_actions}>
                    <button className={`${styles.action_btn} ${styles.start}`} onClick={() => onAction(req, 'MEET_IN')}>🤝 MEET IN</button>
                    <button className={`${styles.action_btn} ${styles.end}`} onClick={() => onAction(req, 'CANCEL_MEET')}>👻 CANCEL</button>
                  </div>
                )}

                {req.status === 'MEET_IN' && (
                  <button className={`${styles.action_btn} ${styles.end} ${styles.full_w}`} onClick={() => onAction(req, 'MEET_OUT')}>🏁 MEET OUT</button>
                )}
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      )}
    </div>
  );
};

import React from 'react';
import { motion } from 'framer-motion';
import { ZoomIn, ZoomOut, RotateCw, Share, Printer, Eye, ChevronLeft, ChevronRight } from 'lucide-react';
import { Visitor } from './types';

interface AadhaarQuickLookProps {
  visitor: Visitor;
  pdfRenderedImage: string | null;
  previewScale: number;
  setPreviewScale: React.Dispatch<React.SetStateAction<number>>;
  setIsPreviewZoomed: (z: boolean) => void;
}

export const AadhaarQuickLook: React.FC<AadhaarQuickLookProps> = ({
  visitor,
  pdfRenderedImage,
  previewScale,
  setPreviewScale,
  setIsPreviewZoomed
}) => {
  if (!pdfRenderedImage) return null;

  return (
    <motion.div 
      className="apple_quicklook_overlay"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      style={{ 
        position: 'fixed', inset: 0, zIndex: 9999,
        background: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(30px)',
        display: 'flex', flexDirection: 'column'
      }}
    >
      <motion.header 
        initial={{ y: -20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        className="quicklook_toolbar"
        style={{ 
          height: '52px', background: 'rgba(45,45,45,0.7)', 
          borderBottom: '1px solid rgba(255,255,255,0.1)',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          padding: '0 20px', userSelect: 'none'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          <div className="window_controls" style={{ display: 'flex', gap: '8px' }}>
            <div onClick={() => setIsPreviewZoomed(false)} style={{ width: '12px', height: '12px', borderRadius: '50%', background: '#FF5F57', cursor: 'pointer' }} />
            <div style={{ width: '12px', height: '12px', borderRadius: '50%', background: '#FFBD2E' }} />
            <div style={{ width: '12px', height: '12px', borderRadius: '50%', background: '#28C940' }} />
          </div>
          <div style={{ color: 'rgba(255,255,255,0.9)', fontSize: '0.85rem', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Eye size={14} /> 
            <span>Aadhaar_Dossier_{visitor._id.substring(visitor._id.length-6)}.pdf</span>
            <span style={{ opacity: 0.4 }}>— 1.2 MB</span>
          </div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          <button className="ql_tool_btn" onClick={() => { setIsPreviewZoomed(false); setPreviewScale(1); }} style={{ padding: '6px 12px', borderRadius: '6px', background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
            Done
          </button>
          <div style={{ width: '1px', height: '20px', background: 'rgba(255,255,255,0.1)', margin: '0 10px' }} />
          <button className="ql_tool_icon" onClick={() => setPreviewScale(prev => Math.min(prev + 0.25, 4))}><ZoomIn size={18} /></button>
          <button className="ql_tool_icon" onClick={() => setPreviewScale(prev => Math.max(prev - 0.25, 0.5))}><ZoomOut size={18} /></button>
          <button className="ql_tool_icon" onClick={() => setPreviewScale(1)} style={{ fontSize: '0.65rem', fontWeight: 900 }}>RESET</button>
          <button className="ql_tool_icon"><RotateCw size={18} /></button>
          <div style={{ width: '1px', height: '20px', background: 'rgba(255,255,255,0.1)', margin: '0 10px' }} />
          <button className="ql_tool_icon"><Share size={18} /></button>
          <button className="ql_tool_icon"><Printer size={18} /></button>
        </div>
      </motion.header>

      <div 
        className="quicklook_body"
        style={{ 
          flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
          padding: '60px', overflow: 'auto', position: 'relative'
        }}
        onClick={() => { setIsPreviewZoomed(false); setPreviewScale(1); }}
      >
        <motion.div 
          drag
          dragConstraints={{ left: -1000, right: 1000, top: -1000, bottom: 1000 }}
          dragElastic={0.1}
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ 
            scale: previewScale, 
            opacity: 1,
            cursor: previewScale > 1 ? 'grab' : 'default'
          }}
          whileDrag={{ cursor: 'grabbing' }}
          className="quicklook_document_container"
          style={{ 
            boxShadow: '0 50px 100px rgba(0,0,0,0.5)',
            borderRadius: '4px', overflow: 'hidden',
            background: 'white',
            touchAction: 'none'
          }}
          onClick={(e) => e.stopPropagation()}
        >
          <img 
            src={pdfRenderedImage} 
            alt="Aadhaar Document" 
            style={{ 
              display: 'block', maxWidth: '85vw', maxHeight: '80vh', 
              objectFit: 'contain', pointerEvents: 'none'
            }} 
          />
        </motion.div>
      </div>

      <footer style={{ height: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '20px', color: 'rgba(255,255,255,0.5)', fontSize: '0.75rem' }}>
        <div style={{ display: 'flex', gap: '10px' }}>
          <ChevronLeft size={16} />
          <span>Page 1 of 1</span>
          <ChevronRight size={16} />
        </div>
      </footer>
    </motion.div>
  );
};

