        <div className="capture_previews" style={{ display: 'grid', gridTemplateColumns: features?.aadhaar ? '1fr' : '1fr 1fr', gap: '12px' }}>
          <div className={`preview_box ${formData.photoUrl ? 'captured' : ''}`} style={{ height: '90px', borderRadius: '16px', background: 'rgba(255,255,255,0.4)', border: '1px solid rgba(0,0,0,0.05)', overflow: 'hidden', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
            {formData.photoUrl ? <img src={formData.photoUrl} alt="Visitor" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <><User size={18} opacity={0.3} /><span style={{ fontSize: '0.55rem', fontWeight: 800, opacity: 0.5 }}>VISITOR</span></>}
          </div>
          {!features?.aadhaar && (
            <div className={`preview_box ${formData.idProofPhotoUrl ? 'captured' : ''}`} style={{ height: '90px', borderRadius: '16px', background: 'rgba(255,255,255,0.4)', border: '1px solid rgba(0,0,0,0.05)', overflow: 'hidden', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
              {formData.idProofPhotoUrl ? <img src={formData.idProofPhotoUrl} alt="ID" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <><ShieldCheck size={18} opacity={0.3} /><span style={{ fontSize: '0.55rem', fontWeight: 800, opacity: 0.5 }}>ID PROOF</span></>}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { motion } from 'framer-motion';
import { Search, UserCheck, MapPin, User, ShieldCheck } from 'lucide-react';
import { SkeletonCard } from '../ui/Skeleton';
import { Visitor, STATUS_CONFIG } from './types';

interface SidebarHistoryProps {
  auditHistory: Visitor[];
  isLoading: boolean;
  visitor: Visitor | null;
  searchQuery: string;
  historyFilter: string;
  setSearchQuery: (q: string) => void;
  setVisitor: (v: Visitor) => void;
  setScanStatus: (s: 'idle' | 'scanning' | 'verifying' | 'success' | 'error') => void;
  handleGrantAccess: (action: 'checkin' | 'completed' | 'forward') => void;
  handleSendAlert: (id: string, type: 'OVERSTAY' | 'POST_MEETING') => void;
  setSelectedPhoto: (photo: { url: string; title: string; isAadhaar?: boolean; id?: string }) => void;
  isAadhaarLicensed?: boolean;
}

export const SidebarHistory: React.FC<SidebarHistoryProps> = ({
  auditHistory,
  isLoading,
  visitor,
  searchQuery,
  historyFilter,
  setSearchQuery,
  setVisitor,
  setScanStatus,
  handleGrantAccess,
  handleSendAlert,
  setSelectedPhoto,
  isAadhaarLicensed = false
}) => {

  const filteredHistory = auditHistory.filter(v => {
    const q = searchQuery.toLowerCase();
    const matchesSearch = v.name.toLowerCase().includes(q) || 
                         v.phone.includes(q) ||
                         v.company?.toLowerCase().includes(q) ||
                         v.hostName?.toLowerCase().includes(q) ||
                         v.hostId?.name?.toLowerCase().includes(q) ||
                         v._id.toLowerCase().includes(q);

    if (historyFilter === 'ALL') return matchesSearch;
    if (historyFilter === 'PENDING') return v.status === 'PENDING_GUARD' && matchesSearch;
    if (historyFilter === 'OVERSTAY') {
      const isOverstay = ['GATE_IN', 'MEET_IN', 'MEET_OUT'].includes(v.status) && v.expectedCheckout && new Date(v.expectedCheckout) < new Date();
      return isOverstay && matchesSearch;
    }
    return v.status === historyFilter && matchesSearch;
  });

  return (
    <aside className="audit_sidebar_kiosk glass_panel">
      <div className="sidebar_header">
        <h3>LOGS</h3>
        <div className="search_mini_wrap">
          <Search size={14} />
          <input 
            placeholder="Search Visitor..." 
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
          />
        </div>
        <div className="live_tag">LIVE HUB</div>
      </div>

      <div className="audit_feed">
        {isLoading ? (
          [1,2,3,4].map(i => <SkeletonCard key={i} />)
        ) : (
          filteredHistory.map((entry) => (
            <motion.div 
              key={entry._id} 
              className={`feed_card_pro ${visitor?._id === entry._id ? 'selected_dossier' : ''}`}
              onClick={() => { setVisitor(entry); setScanStatus('success'); }}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
            >
              <div className="feed_header">
                <div style={{ display: 'flex', gap: '14px' }}>
                  <div className="v_photo_mini">
                    <img src={entry.photoUrl || `https://ui-avatars.com/api/?name=${encodeURIComponent(entry.name)}&background=random&color=fff`} alt={entry.name} />

                  </div>
                  <div className="visitor_meta">
                    <div className="v_codename">V-{entry._id.slice(-6).toUpperCase()}</div>
                    <div className="v_fullname">{entry.name}</div>
                    <div className="v_company_mini">{entry.company || 'Private Visit'}</div>
                  </div>
                </div>
                <div className={`v_status_badge ${STATUS_CONFIG[entry.status]?.class || 'chip_pending'}`}>
                  {STATUS_CONFIG[entry.status]?.label || entry.status.replace(/_/g, ' ')}
                </div>
              </div>

              <div className="feed_details">
                <div className="detail_box">
                  <label><UserCheck size={10} /> Host</label>
                  <span>{entry.hostName}</span>
                </div>
                <div className="detail_box">
                  <label><MapPin size={10} /> Purpose</label>
                  <span>{entry.purpose}</span>
                </div>
              </div>

              <div className="timestamp_grid_v3">
                <div className="ts_node"><span>Applied</span><strong>{new Date(entry.createdAt).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</strong></div>
                <div className={`ts_node ${entry.approvedAt ? 'active' : ''}`}><span>Approved</span><strong>{entry.approvedAt ? new Date(entry.approvedAt).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '--:--'}</strong></div>
                <div className={`ts_node ${entry.checkInTime ? 'active' : ''}`}><span>GATE IN</span><strong>{entry.checkInTime ? new Date(entry.checkInTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '--:--'}</strong></div>
                <div className={`ts_node ${entry.meetInTime ? 'active' : ''}`}><span>MEET IN</span><strong>{entry.meetInTime ? new Date(entry.meetInTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '--:--'}</strong></div>
                <div className={`ts_node ${entry.meetOutTime ? 'active' : ''}`}><span>MEET OUT</span><strong>{entry.meetOutTime ? new Date(entry.meetOutTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '--:--'}</strong></div>
                <div className={`ts_node ${entry.checkOutTime ? 'active' : ''}`}><span>GATE OUT</span><strong>{entry.checkOutTime ? new Date(entry.checkOutTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '--:--'}</strong></div>
              </div>

              <div className="card_actions_area">
                <div style={{ display: 'flex', gap: '8px', marginBottom: '8px', flexWrap: 'wrap' }}>
                  {entry.photoUrl && (
                    <button 
                      className="glass-btn secondary" 
                      style={{ padding: '4px 8px', fontSize: '0.6rem', background: 'rgba(0,0,0,0.05)' }}
                      onClick={(e) => { e.stopPropagation(); setSelectedPhoto({ url: entry.photoUrl!, title: `Visitor: ${entry.name}` }); }}
                    >
                      <User size={10} /> Photo
                    </button>
                  )}
                  {entry.idProofPhotoUrl && (
                    <button 
                      className="glass-btn secondary" 
                      style={{ padding: '4px 8px', fontSize: '0.6rem', background: 'var(--apple-blue)', color: 'white' }}
                      onClick={(e) => { e.stopPropagation(); setSelectedPhoto({ url: entry.idProofPhotoUrl!, title: `ID Proof: ${entry.name}` }); }}
                    >
                      <ShieldCheck size={10} /> ID Proof
                    </button>
                  )}
                  {entry.aadhaarImageUrl && (
                    <button 
                      className="glass-btn secondary" 
                      style={{ padding: '4px 8px', fontSize: '0.6rem', background: 'var(--apple-orange)', color: 'white' }}
                      onClick={(e) => { e.stopPropagation(); setSelectedPhoto({ url: entry.aadhaarImageUrl!, title: `Aadhaar: ${entry.name}`, isAadhaar: true, id: entry._id }); }}
                    >
                      <ShieldCheck size={10} /> Aadhaar
                    </button>
                  )}
                </div>

                {entry.status === 'PENDING_GUARD' && (
                  <button 
                    className="glass-btn primary" 
                    style={{ 
                      background: (entry.aadhaarVerified || !isAadhaarLicensed) ? 'var(--apple-blue)' : 'var(--apple-blue)', 
                      padding: '8px', 
                      fontSize: '0.65rem', 
                      opacity: (entry.aadhaarVerified || !isAadhaarLicensed) ? 1 : 0.5 
                    }} 
                    onClick={(e) => { 
                      e.stopPropagation(); 
                      setVisitor(entry); 
                      if (entry.aadhaarVerified || !isAadhaarLicensed) {
                        handleGrantAccess('forward');
                      } else {
                        alert('Please open details and verify Aadhaar first.');
                      }
                    }}
                  >
                    {entry.aadhaarVerified ? 'FORWARDED' : (isAadhaarLicensed ? 'REQUIRE AADHAAR' : 'FORWARD TO HOST')}
                  </button>
                )}
                {entry.status === 'APPROVED' && (
                  <button className="glass-btn primary" style={{ background: 'var(--apple-green)', padding: '8px', fontSize: '0.65rem' }} onClick={(e) => { e.stopPropagation(); setVisitor(entry); handleGrantAccess('checkin'); }}>
                    GRANT PHYSICAL ENTRY
                  </button>
                )}
                {['GATE_IN', 'MEET_IN', 'MEET_OUT', 'CHECKED_IN', 'IN_MEETING'].includes(entry.status) && (
                  <div className="action_row_inline">
                    <button className="glass-btn primary" style={{ background: 'var(--apple-red)', flex: 1, padding: '8px', fontSize: '0.65rem' }} onClick={(e) => { e.stopPropagation(); setVisitor(entry); handleGrantAccess('completed'); }}>
                      GATE OUT
                    </button>
                    {entry.expectedCheckout && new Date(entry.expectedCheckout) < new Date() && (
                      <button className="glass-btn primary" style={{ background: 'var(--apple-red)', flex: 1, padding: '8px', fontSize: '0.65rem' }} onClick={(e) => { e.stopPropagation(); handleSendAlert(entry._id, 'OVERSTAY'); }}>
                        🚨 ALERT
                      </button>
                    )}
                    {entry.status === 'MEET_OUT' && !(entry.expectedCheckout && new Date(entry.expectedCheckout) < new Date()) && (
                      <button className="glass-btn primary" style={{ background: 'var(--apple-orange)', flex: 1, padding: '8px', fontSize: '0.65rem' }} onClick={(e) => { e.stopPropagation(); handleSendAlert(entry._id, 'POST_MEETING'); }}>
                        🔔 REMIND
                      </button>
                    )}
                  </div>
                )}
              </div>
            </motion.div>
          ))
        )}
      </div>
    </aside>
  );
};

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Phone, UserCheck, Info, Clock, Shield, RefreshCw, LogIn, LogOut, ArrowRight, XCircle, Upload } from 'lucide-react';
import { useTenant } from '../../app/TenantContext';
import { ActiveTimer } from './ActiveTimer';
import { Visitor, STATUS_CONFIG } from './types';

interface VisitorDossierProps {
  visitor: Visitor;
  setScanStatus: (s: 'idle') => void;
  aadhaarReviewData: any;
  uidaiWindow: Window | null;
  aadhaarPassword: string;
  isUploadingAadhaar: boolean;
  pdfRenderedImage: string | null;
  handleOpenUidai: () => void;
  handleStep2Interact: () => void;
  setAadhaarPassword: (pwd: string) => void;
  handleAadhaarUpload: (file: File | null | undefined, id: string) => void;
  handleAutoFetchLatest: (id: string) => void;
  fetchedFile: File | null;
  setIsPreviewZoomed: (z: boolean) => void;
  handleAadhaarConfirm: () => void;
  handleAadhaarReject: () => void;
  handleGrantAccess: (action: 'checkin' | 'completed' | 'forward') => void;
  handleSendAlert: (id: string, type: 'OVERSTAY' | 'POST_MEETING') => void;
  guardConfig?: any;
}

export const VisitorDossier: React.FC<VisitorDossierProps> = ({
  visitor,
  setScanStatus,
  aadhaarReviewData,
  uidaiWindow,
  aadhaarPassword,
  isUploadingAadhaar,
  pdfRenderedImage,
  handleOpenUidai,
  handleStep2Interact,
  setAadhaarPassword,
  handleAadhaarUpload,
  handleAutoFetchLatest,
  fetchedFile,
  setIsPreviewZoomed,
  handleAadhaarConfirm,
  handleAadhaarReject,
  handleGrantAccess,
  handleSendAlert,
  guardConfig
}) => {
  const { tenant } = useTenant();
  const isAadhaarLicensed = tenant?.features?.aadhaar;

  const handlePrint = () => {
    const printUrl = `/pass?id=${visitor._id}&print=true&mode=${guardConfig?.printMode || 'HARD_PRINT_BOTH'}`;
    const printWindow = window.open(printUrl, '_blank');
    if (printWindow) {
      printWindow.onload = () => {
        printWindow.print();
      };
    }
  };

  return (
    <motion.div className="dossier_container" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}>
      <div className="dossier_header">
        <div className="dossier_avatar">
          <img src={visitor.photoUrl || `https://ui-avatars.com/api/?name=${encodeURIComponent(visitor.name)}&background=random&color=fff`} alt={visitor.name} />
        </div>
        <div className="dossier_meta">
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <h2>{visitor.name}</h2>
            <div className={`v_status_badge ${STATUS_CONFIG[visitor.status]?.class || 'chip_pending'}`}>
              {STATUS_CONFIG[visitor.status]?.label || visitor.status.replace(/_/g, ' ')}
            </div>
          </div>
          <p>{visitor.company || 'Private Visit'}</p>
          <div style={{ display: 'flex', gap: '15px', marginTop: '8px' }}>
            <span style={{ fontSize: '0.8rem', fontWeight: 800, opacity: 0.6 }}><Phone size={12} style={{ verticalAlign: 'middle', marginRight: '4px' }}/> {visitor.phone}</span>
          </div>
        </div>
      </div>

      <div className="dossier_section_label">Visit Profile</div>
      <div className="feed_details" style={{ border: 'none', padding: 0 }}>
        <div className="detail_box">
          <label><UserCheck size={10} /> Contact Person</label>
          <span>{visitor.hostName}</span>
        </div>
        <div className="detail_box">
          <label><Info size={10} /> Purpose</label>
          <span>{visitor.purpose}</span>
        </div>
        {visitor.requestedDuration && (
          <div className="detail_box">
            <label><Clock size={10} /> Requested Duration</label>
            <span>{visitor.requestedDuration}</span>
          </div>
        )}
        {visitor.expectedCheckout && ['GATE_IN', 'MEET_IN', 'MEET_OUT'].includes(visitor.status) && (
          <div className="detail_box">
            <label><Clock size={10} /> Live Session Timer</label>
            <ActiveTimer expectedCheckout={visitor.expectedCheckout} />
          </div>
        )}
      </div>

      {visitor.hostRemark && (
        <div style={{ marginTop: '16px', padding: '12px', background: 'rgba(0,122,255,0.05)', borderRadius: '12px', borderLeft: '4px solid var(--apple-blue)' }}>
          <div style={{ fontSize: '0.6rem', fontWeight: 950, color: 'var(--apple-blue)', textTransform: 'uppercase', marginBottom: '4px' }}>Host Instructions</div>
          <div style={{ fontSize: '0.85rem', fontWeight: 700 }}>&quot;{visitor.hostRemark}&quot;</div>
        </div>
      )}

      <div className="dossier_section_label">Log History</div>
      <div className="timestamp_dossier">
        <div className="ts_box">
          <label>Applied</label>
          <strong>{new Date(visitor.createdAt).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</strong>
        </div>
        <div className={`ts_box ${visitor.approvedAt ? 'highlight' : ''}`}>
          <label>Approved</label>
          <strong>{visitor.approvedAt ? new Date(visitor.approvedAt).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) : '--:--'}</strong>
        </div>
        <div className={`ts_box ${visitor.checkInTime ? 'highlight' : ''}`}>
          <label>GATE IN</label>
          <strong>{visitor.checkInTime ? new Date(visitor.checkInTime).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) : '--:--'}</strong>
        </div>
        <div className={`ts_box ${visitor.meetInTime ? 'highlight' : ''}`}>
          <label>MEET IN</label>
          <strong>{visitor.meetInTime ? new Date(visitor.meetInTime).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) : '--:--'}</strong>
        </div>
        <div className={`ts_box ${visitor.meetOutTime ? 'highlight' : ''}`}>
          <label>MEET OUT</label>
          <strong>{visitor.meetOutTime ? new Date(visitor.meetOutTime).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) : '--:--'}</strong>
        </div>
        <div className={`ts_box ${visitor.checkOutTime ? 'highlight' : ''}`}>
          <label>GATE OUT</label>
          <strong>{visitor.checkOutTime ? new Date(visitor.checkOutTime).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) : '--:--'}</strong>
        </div>
      </div>

      <div className="dossier_section_label">Security Actions</div>
      <div className="dossier_actions">
        {visitor.status === 'PENDING_GUARD' && (
